/**
 * Handles the gnosis derive Formal Ledger Bundle workflow.
 */
export function deriveFormalLedgerBundle(
  context: FormalLedgerContext
): FormalLedgerBundle {
  const reports = {
    voidWalking: createVoidWalkingReport(context.personality),
    negotiation: createNegotiationReport(context.negotiation),
    community: createCommunityReport(context.community),
    metacognition: createMetacognitionReport(context.metacognition),
    recovery: createRecoveryReport(context.recovery),
    probability: createProbabilityReport(context.probability),
  } satisfies Record<FormalLedgerFamilyId, FormalLedgerFamilyReport>;

  const activeFamilies = FORMAL_LEDGER_FAMILIES.filter(
    (familyId) => reports[familyId].active
  );
  const bundlePrimitives = aggregateBundlePrimitives(reports, activeFamilies);
  const diagnostics = activeFamilies.flatMap(
    (familyId) => reports[familyId].diagnostics
  );
  const narratives = activeFamilies.flatMap(
    (familyId) => reports[familyId].narratives
  );
  const recommendations = activeFamilies.flatMap(
    (familyId) => reports[familyId].recommendations
  );
  const visualizations = activeFamilies.map(
    (familyId) => reports[familyId].visualization
  );
  const compliance = createCompliance(context.declaration, activeFamilies);
  const complianceDiagnostic = createComplianceDiagnostic(compliance);
  const generatedAt = context.generatedAt ?? new Date().toISOString();
  const statisticalMechanics =
    createFormalLedgerStatisticalMechanicsAccounting();
  const sourceMenu = Array.from(
    new Set([
      ...FORMAL_LEDGER_FAMILIES.flatMap(
        (familyId) => reports[familyId].sources
      ),
      ...statisticalMechanics.sourceRefs,
    ])
  );

  return {
    generatedAt,
    ...(context.declaration !== undefined
      ? { declaration: context.declaration }
      : {}),
    familyOrder: FORMAL_LEDGER_FAMILIES,
    activeFamilies,
    primitives: bundlePrimitives,
    reports,
    diagnostics:
      complianceDiagnostic == null
        ? diagnostics
        : [...diagnostics, complianceDiagnostic],
    narratives,
    recommendations,
    visualizations,
    statisticalMechanics,
    sourceMenu,
    compliance,
  };
}

/**
 * Creates the Formal Ledger Statistical Mechanics Accounting.
 */
export function createFormalLedgerStatisticalMechanicsAccounting(): FormalLedgerStatisticalMechanicsAccounting {
  const certificate = createStatisticalMechanicsAccounting();
  if (certificate === null) {
    throw new Error(
      'Exact statistical mechanics accounting certificate could not be derived from the formal mesh-policy surface.'
    );
  }
  const metrology = createGnosticMetrologyProfile(certificate);
  if (metrology === null) {
    throw new Error(
      'Exact gnostic metrology profile could not be derived from the statistical mechanics accounting certificate.'
    );
  }
  const pressureGradient = createPressureGradientCertificate(metrology);
  if (pressureGradient === null) {
    throw new Error(
      'Exact pressure-gradient certificate could not be derived from the gnostic metrology profile.'
    );
  }
  const braidPacket = createBraidPacketCertificate(0, certificate);
  if (braidPacket === null) {
    throw new Error(
      'Exact braid-packet certificate could not be derived from the statistical mechanics accounting certificate.'
    );
  }
  const extendedAeon = createExtendedAeonTransitionCertificate(braidPacket);
  if (extendedAeon === null) {
    throw new Error(
      'Exact extended-aeon certificate could not be derived from the braid packet certificate.'
    );
  }
  const interferePort = createGnosisUringInterferePortCertificate(extendedAeon);
  if (interferePort === null) {
    throw new Error(
      'Exact gnosis-uring interfere-port certificate could not be derived from the extended-aeon certificate.'
    );
  }
  const interferenceStride = createInterferenceStrideCertificate(braidPacket);
  if (interferenceStride === null) {
    throw new Error(
      'Exact interference-stride certificate could not be derived from the braid packet certificate.'
    );
  }
  const pressureWeightedInterference =
    createPressureWeightedInterferenceStrideCertificate(interferenceStride);
  if (pressureWeightedInterference === null) {
    throw new Error(
      'Exact pressure-weighted interference certificate could not be derived from the interference-stride certificate.'
    );
  }
  const gnosticLensGeometry = createGnosticLensGeometryCertificate(braidPacket);
  if (gnosticLensGeometry === null) {
    throw new Error(
      'Exact gnostic-lens geometry certificate could not be derived from the braid packet certificate.'
    );
  }

  return {
    source: 'GnosisFormalLedgerStatisticalMechanicsAccounting',
    certificate,
    metrology,
    pressureGradient,
    braidPacket,
    extendedAeon,
    interferePort,
    interferenceStride,
    pressureWeightedInterference,
    gnosticLensGeometry,
    summary:
      'Exact 10/30/90 saturation accounting over the 12-row Aeon budget: 1560 gG total mass, 96 SPa total pressure, with the 43 interfere port certified as a terminal gnosis-uring handoff, pressure-weighted stride anchor, and finite gnostic-lens geometry certificate.',
    sourceRefs: [
      'lean/Lean/ForkRaceFoldTheorems/GamutBraid.lean',
      'lean/Lean/ForkRaceFoldTheorems/StatisticalMechanicsAccounting.lean',
      'src/mesh-policy.ts',
      'open-source/gnosis/FORMAL_LEDGER.md#statistical-mechanics-accounting-information-beach',
    ],
  };
}

/**
 * Creates the Probability Formal Ledger Input.
 */
export function createProbabilityFormalLedgerInput(
  analysis: FormalLedgerProbabilityAnalysis
): FormalLedgerProbabilityInput {
  const topPosterior =
    analysis.hypothesisRanking[0]?.posteriorProbability ?? 0.5;
  const runnerUpPosterior =
    analysis.hypothesisRanking[1]?.posteriorProbability ?? 0;
  const hypothesisCount = analysis.hypothesisRanking.length;
  const unsupportedClaimRatio =
    hypothesisCount === 0
      ? 0
      : analysis.evidenceAudit.unsupportedClaims.length / hypothesisCount;
  const updateStrength = average(
    analysis.hypothesisRanking.map((entry) =>
      Math.abs(entry.posteriorProbability - entry.priorProbability)
    )
  );

  return {
    hypothesisCount,
    topPosterior,
    runnerUpPosterior,
    evidenceTraceability: analysis.evidenceAudit.traceabilityCoverage,
    unsupportedClaimRatio,
    validationStrength: deriveProbabilityValidationStrength(
      analysis.validation
    ),
    updateStrength,
    convergenceRate: clampUnit(analysis.diagnostics.convergence.observedRate),
    source: '@a0n/maybe probability analysis',
  };
}

/**
 * Handles the gnosis derive Probability Formal Ledger Bundle workflow.
 */
export function deriveProbabilityFormalLedgerBundle(
  analysis: FormalLedgerProbabilityAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerBundle {
  return deriveFormalLedgerBundle(
    buildFormalLedgerContext(declaration, {
      probability: createProbabilityFormalLedgerInput(analysis),
    })
  );
}

/**
 * Creates the Metacognition Formal Ledger Context.
 */
export function createMetacognitionFormalLedgerContext(
  analysis: FormalLedgerMetacognitionAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  if (!hasMetacognitionAnalysisSignal(analysis)) {
    return buildFormalLedgerContext(declaration);
  }

  const calibrationLayers = analysis.calibration.layers ?? [];
  const rawConfidenceValues = calibrationLayers
    .map((layer) => layer.rawConfidence)
    .filter((value): value is number => Number.isFinite(value));
  const calibratedConfidenceValues = calibrationLayers
    .map((layer) => layer.calibratedConfidence)
    .filter((value): value is number => Number.isFinite(value));
  const dataQualityValues = calibrationLayers
    .map((layer) => layer.dataQuality)
    .filter((value): value is number => Number.isFinite(value));
  const credibleIntervalWidths = calibrationLayers
    .map((layer) => {
      if (layer.credibleInterval == null) {
        return undefined;
      }

      return clampUnit(layer.credibleInterval[1] - layer.credibleInterval[0]);
    })
    .filter((value): value is number => Number.isFinite(value));
  const layerAlignmentScores = (analysis.coherence.layerAlignmentScores ?? [])
    .filter((value): value is number => Number.isFinite(value))
    .map(clampUnit);
  const rawConfidence = averageOrDefault(
    rawConfidenceValues,
    clampUnit(analysis.calibration.overallConfidence ?? 0.5)
  );
  const calibratedConfidence = averageOrDefault(
    calibratedConfidenceValues,
    rawConfidence
  );
  const dataQuality = averageOrDefault(dataQualityValues, calibratedConfidence);
  const intervalWidth = averageOrDefault(credibleIntervalWidths, 0.35);
  const overallCoherence = clampUnit(
    analysis.coherence.overallCoherence ??
      averageOrDefault(layerAlignmentScores, 0.5)
  );
  const coherenceImprovement = clampUnit(
    analysis.coherence.coherenceImprovement ?? overallCoherence
  );
  const remainingTensionCount = Math.max(
    0,
    Math.round(analysis.coherence.remainingTensionCount ?? 0)
  );
  const resolvedContradictionCount = Math.max(
    0,
    Math.round(analysis.coherence.resolvedContradictionCount ?? 0)
  );
  const totalContradictions =
    remainingTensionCount + resolvedContradictionCount;
  const resolvedRatio =
    totalContradictions === 0
      ? 1
      : clampUnit(resolvedContradictionCount / totalContradictions);
  const layerAlignment = averageOrDefault(
    layerAlignmentScores,
    overallCoherence
  );
  const detectedCount = Math.max(
    0,
    Math.round(analysis.bias.detectedCount ?? 0)
  );
  const correctedCount = Math.max(
    0,
    Math.round(analysis.bias.correctedCount ?? detectedCount)
  );
  const correctedRatio =
    detectedCount === 0 ? 1 : clampUnit(correctedCount / detectedCount);
  const correctionConfidence = clampUnit(
    analysis.bias.confidenceInCorrections ?? 0.5
  );
  const affectedLayerBreadth = clampUnit(
    analysis.bias.affectedLayerBreadth ??
      (detectedCount === 0 ? 0.5 : correctedRatio)
  );
  const debiasedPressure = clampUnit(analysis.bias.totalDebiasedDelta ?? 0);
  const overallQuality = clampUnit(
    analysis.quality?.overallQuality ??
      averageOrDefault(
        [calibratedConfidence, overallCoherence, correctionConfidence],
        0.5
      )
  );

  return buildFormalLedgerContext(declaration, {
    metacognition: {
      c0Confidence: averageOrDefault(
        [rawConfidence, dataQuality, overallQuality],
        rawConfidence
      ),
      c1Calibration: averageOrDefault(
        [calibratedConfidence, dataQuality, 1 - intervalWidth, overallQuality],
        calibratedConfidence
      ),
      c2Coherence: averageOrDefault(
        [
          overallCoherence,
          coherenceImprovement,
          layerAlignment,
          resolvedRatio,
          overallQuality,
        ],
        overallCoherence
      ),
      c3BiasAwareness: averageOrDefault(
        [
          correctionConfidence,
          correctedRatio,
          affectedLayerBreadth,
          1 - debiasedPressure,
          overallQuality,
        ],
        correctionConfidence
      ),
      source: analysis.source ?? 'gnosis metacognition analysis',
    },
  });
}

/**
 * Handles the gnosis derive Metacognition Formal Ledger Bundle workflow.
 */
export function deriveMetacognitionFormalLedgerBundle(
  analysis: FormalLedgerMetacognitionAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerBundle {
  return deriveFormalLedgerBundle(
    createMetacognitionFormalLedgerContext(analysis, declaration)
  );
}

/**
 * Creates the Recovery Formal Ledger Context.
 */
export function createRecoveryFormalLedgerContext(
  analysis: FormalLedgerRecoveryAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  if (!hasRecoveryAnalysisSignal(analysis)) {
    return buildFormalLedgerContext(declaration);
  }

  const indicators = analysis.markers?.indicators ?? [];
  const recoveryFactors = analysis.markers?.recoveryFactors ?? [];
  const confidence = clampUnit(analysis.signals.confidence ?? 0.5);
  const burnoutRisk = clampUnit(analysis.signals.burnoutRisk ?? 0.5);
  const recoveryTimeLoad =
    typeof analysis.signals.recoveryTimeMinutes === 'number' &&
    Number.isFinite(analysis.signals.recoveryTimeMinutes)
      ? normalizeCount(Math.max(0, analysis.signals.recoveryTimeMinutes), 240)
      : averageOrDefault([burnoutRisk, confidence], 0.5);
  const stressLoad = clampUnit(
    analysis.signals.stressLoad ??
      averageOrDefault([burnoutRisk, recoveryTimeLoad], 0.5)
  );
  const indicatorLoad = normalizeCount(indicators.length, 4);
  const recoveryFactorSupport = normalizeCount(recoveryFactors.length, 4);
  const breathSignal = keywordSignalScore(recoveryFactors, [
    'breath',
    'breathing',
    'exhale',
    'inhale',
    'regulat',
    'calm',
  ]);
  const restSignal = keywordSignalScore(recoveryFactors, [
    'sleep',
    'rest',
    'recover',
    'restore',
    'break',
    'pause',
  ]);
  const forgivenessSignal = keywordSignalScore(recoveryFactors, [
    'forgive',
    'release',
    'accept',
    'grace',
    'compassion',
  ]);
  const ruminationSignal = keywordSignalScore(indicators, [
    'ruminat',
    'replay',
    'spiral',
    'loop',
    'catastroph',
    'obsess',
    'defensive',
  ]);
  const restoration = clampUnit(
    analysis.signals.restorationCapacity ??
      averageOrDefault(
        [
          1 - stressLoad,
          1 - burnoutRisk,
          recoveryFactorSupport,
          restSignal,
          confidence,
        ],
        0.5
      )
  );
  const sleepDebt = clampUnit(
    analysis.signals.sleepDebt ??
      averageOrDefault(
        [recoveryTimeLoad, burnoutRisk, 1 - restSignal, indicatorLoad],
        0.5
      )
  );
  const forgiveness = clampUnit(
    analysis.signals.forgiveness ??
      averageOrDefault(
        [forgivenessSignal, restoration, 1 - ruminationSignal],
        0.5
      )
  );
  const breathRegulation = clampUnit(
    analysis.signals.breathRegulation ??
      averageOrDefault([breathSignal, 1 - stressLoad, confidence], 0.45)
  );
  const rumination = clampUnit(
    analysis.signals.ruminationRisk ??
      averageOrDefault(
        [ruminationSignal, stressLoad, recoveryTimeLoad, indicatorLoad],
        0.5
      )
  );

  return buildFormalLedgerContext(declaration, {
    recovery: {
      stressLoad,
      sleepDebt,
      restoration,
      forgiveness,
      breathRegulation,
      rumination,
      source: analysis.source ?? 'gnosis recovery analysis',
    },
  });
}

/**
 * Handles the gnosis derive Recovery Formal Ledger Bundle workflow.
 */
export function deriveRecoveryFormalLedgerBundle(
  analysis: FormalLedgerRecoveryAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerBundle {
  return deriveFormalLedgerBundle(
    createRecoveryFormalLedgerContext(analysis, declaration)
  );
}

/**
 * Creates the Justice Formal Ledger Context.
 */
export function createJusticeFormalLedgerContext(
  analysis: FormalLedgerJusticeAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  if (!hasJusticeAnalysisSignal(analysis)) {
    return buildFormalLedgerContext(declaration);
  }

  const evidence = analysis.evidence;
  const adjudication = analysis.adjudication;
  const process = analysis.process;
  const totalThreads = Math.max(
    1,
    Math.round(
      evidence.totalThreads ??
        Math.max(
          0,
          (evidence.coveredThreads ?? 0) +
            (evidence.contestedThreads ?? 0) +
            (evidence.uncoveredThreads ?? 0)
        )
    )
  );
  const coveredThreads = Math.max(
    0,
    evidence.coveredThreads ?? totalThreads - (evidence.uncoveredThreads ?? 0)
  );
  const contestedThreads = Math.max(0, evidence.contestedThreads ?? 0);
  const uncoveredThreads = Math.max(
    0,
    evidence.uncoveredThreads ??
      Math.max(totalThreads - coveredThreads - contestedThreads, 0)
  );
  const coverageRatio = clampUnit(coveredThreads / totalThreads);
  const contestedRatio = clampUnit(contestedThreads / totalThreads);
  const uncoveredRatio = clampUnit(uncoveredThreads / totalThreads);
  const evidenceDeficit = clampUnit(
    evidence.evidenceDeficit == null
      ? averageOrDefault([uncoveredRatio, contestedRatio], 0.35)
      : normalizeCount(evidence.evidenceDeficit, Math.max(2, totalThreads))
  );
  const averageConfidence = clampUnit(
    evidence.averageConfidence ??
      averageOrDefault(
        [coverageRatio, 1 - contestedRatio, 1 - uncoveredRatio],
        0.5
      )
  );
  const criticalIssueLoad = normalizeCount(
    process?.criticalIssueCount ?? 0,
    Math.max(2, totalThreads)
  );
  const injusticeTriggerLoad = normalizeCount(
    process?.injusticeTriggerCount ?? 0,
    Math.max(2, totalThreads)
  );
  const remedyCandidateCount = Math.max(
    0,
    adjudication?.remedyCandidateCount ?? adjudication?.rankedRemedyCount ?? 0
  );
  const remedyCountScore = normalizeCount(remedyCandidateCount, 4);
  const recommendedActionCoverage = normalizeCount(
    process?.recommendedActionCount ?? remedyCandidateCount,
    Math.max(2, totalThreads)
  );
  const summaryClarity = clampUnit(
    process?.summaryClarity ??
      averageOrDefault([recommendedActionCoverage, 1 - criticalIssueLoad], 0.5)
  );
  const ratificationRequired = adjudication?.ratificationRequired === true;
  const enforcementActive = adjudication?.enforcementActive === true;
  const appealAvailable = adjudication?.appealAvailable === true;
  const communitySignalBreadth = normalizeCount(
    adjudication?.communitySignalCount ??
      adjudication?.affectedCommunityCount ??
      0,
    4
  );
  const readiness = (() => {
    if (evidence.sufficient === true) {
      return 0.9;
    }

    switch (adjudication?.status) {
      case 'adjudicated_remedy':
      case 'mediated_settlement':
        return 0.82;
      case 'ratification_required':
        return 0.58;
      default:
        return 0.28;
    }
  })();
  const selectedRemedyConfidence =
    adjudication?.status === 'adjudicated_remedy' ||
    adjudication?.status === 'mediated_settlement'
      ? 0.82
      : adjudication?.status === 'ratification_required'
      ? 0.58
      : 0.35;
  const dominanceRisk = averageOrDefault(
    [
      criticalIssueLoad,
      injusticeTriggerLoad,
      uncoveredRatio,
      enforcementActive ? 0.78 : 0.34,
    ],
    0.5
  );

  return buildFormalLedgerContext(declaration, {
    probability: {
      hypothesisCount: Math.max(2, remedyCandidateCount || totalThreads),
      topPosterior: averageOrDefault(
        [coverageRatio, averageConfidence, readiness, 1 - criticalIssueLoad],
        0.5
      ),
      runnerUpPosterior: averageOrDefault(
        [
          contestedRatio,
          uncoveredRatio,
          injusticeTriggerLoad,
          ratificationRequired ? 0.64 : 0.28,
        ],
        0.35
      ),
      evidenceTraceability: averageOrDefault(
        [coverageRatio, averageConfidence, 1 - uncoveredRatio, summaryClarity],
        0.5
      ),
      unsupportedClaimRatio: averageOrDefault(
        [uncoveredRatio, criticalIssueLoad],
        0.25
      ),
      validationStrength: averageOrDefault(
        [
          1 - evidenceDeficit,
          readiness,
          summaryClarity,
          recommendedActionCoverage,
        ],
        0.5
      ),
      updateStrength: averageOrDefault(
        [
          1 - criticalIssueLoad,
          1 - injusticeTriggerLoad,
          recommendedActionCoverage,
          appealAvailable ? 0.72 : 0.46,
        ],
        0.5
      ),
      convergenceRate: averageOrDefault(
        [readiness, 1 - contestedRatio, remedyCountScore],
        0.5
      ),
      source: analysis.source ?? 'gnosis justice evidence surface',
    },
    community: {
      empathy: averageOrDefault(
        [
          communitySignalBreadth,
          recommendedActionCoverage,
          1 - criticalIssueLoad,
        ],
        0.5
      ),
      belonging: averageOrDefault(
        [
          communitySignalBreadth,
          1 - injusticeTriggerLoad,
          enforcementActive ? 0.32 : 0.68,
        ],
        0.5
      ),
      dominanceRisk,
      mergePressure: averageOrDefault(
        [
          ratificationRequired ? 0.78 : 0.42,
          criticalIssueLoad,
          1 - summaryClarity,
        ],
        0.5
      ),
      reciprocity: averageOrDefault(
        [
          recommendedActionCoverage,
          coverageRatio,
          communitySignalBreadth,
          appealAvailable ? 0.68 : 0.45,
        ],
        0.5
      ),
      source: analysis.source ?? 'gnosis justice community field',
    },
    metacognition: {
      c0Confidence: averageOrDefault([averageConfidence, coverageRatio], 0.5),
      c1Calibration: averageOrDefault(
        [coverageRatio, 1 - evidenceDeficit, summaryClarity],
        0.5
      ),
      c2Coherence: averageOrDefault(
        [
          1 - contestedRatio,
          1 - criticalIssueLoad,
          recommendedActionCoverage,
          selectedRemedyConfidence,
        ],
        0.5
      ),
      c3BiasAwareness: averageOrDefault(
        [
          appealAvailable ? 0.78 : 0.42,
          ratificationRequired ? 0.72 : 0.48,
          communitySignalBreadth,
        ],
        0.5
      ),
      source: analysis.source ?? 'gnosis justice metacognitive audit',
    },
  });
}

