/**
 * Creates the Negotiation Formal Ledger Context.
 */
export function createNegotiationFormalLedgerContext(
  analysis: FormalLedgerNegotiationAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  const primary =
    NEGOTIATION_MODE_SCORES[analysis.tkiLikeSummary.primaryMode] ??
    NEGOTIATION_MODE_SCORES.compromising;
  const secondary =
    NEGOTIATION_MODE_SCORES[analysis.tkiLikeSummary.secondaryMode] ??
    NEGOTIATION_MODE_SCORES.compromising;
  const alignmentValues = [
    ...analysis.bazaar.rounds.map((round) => round.alignment),
    ...(analysis.bazaar.trajectory?.map((step) => step.alignment) ?? []),
    analysis.bazaar.strategicPressure?.alignment,
  ].filter((value): value is number => Number.isFinite(value));
  const alignmentAverage = averageOrDefault(alignmentValues, 0.55);
  const escalationRisk = clampUnit(
    analysis.bazaar.strategicPressure?.escalationRisk ?? 0.5
  );
  const settlementPressure = clampUnit(
    analysis.bazaar.strategicPressure?.settlementPressure ?? 0.5
  );
  const volatility = clampUnit(
    analysis.bazaar.strategicPressure?.volatility ?? 0.5
  );
  const neutralConfidence = clampUnit(
    analysis.neutral.settlementCandidates[0]?.confidence ?? 0.55
  );
  const pressureRisk =
    NEGOTIATION_PRESSURE_BIAS_RISK[
      analysis.neutralSettlementBias.pressureBias ?? 'hold'
    ];

  return buildFormalLedgerContext(declaration, {
    negotiation: {
      assertiveness: averageOrDefault(
        [primary.assertiveness, secondary.assertiveness],
        0.5
      ),
      cooperation: averageOrDefault(
        [primary.cooperation, secondary.cooperation],
        0.5
      ),
      batnaStrength: averageOrDefault(
        [
          (analysis.bazaar.branchOutcomes?.length ?? 0) > 0 ? 0.65 : 0.4,
          alignmentAverage,
          analysis.bazaar.settled ? 0.7 : 0.45,
        ],
        0.5
      ),
      watnaRisk: averageOrDefault(
        [pressureRisk, escalationRisk, 1 - alignmentAverage],
        0.5
      ),
      settlementReadiness: averageOrDefault(
        [
          neutralConfidence,
          settlementPressure,
          analysis.neutral.convergenceStatus === 'settled' ? 0.9 : 0.35,
        ],
        0.5
      ),
      trustReserve: averageOrDefault([alignmentAverage, 1 - volatility], 0.5),
      source: 'aeon bazaar + neutral profile',
    },
    community: {
      empathy: averageOrDefault([alignmentAverage, neutralConfidence], 0.5),
      belonging:
        analysis.neutral.convergenceStatus === 'settled'
          ? averageOrDefault([neutralConfidence, 0.8], 0.7)
          : averageOrDefault([neutralConfidence, 0.45], 0.45),
      dominanceRisk: averageOrDefault([pressureRisk, escalationRisk], 0.5),
      mergePressure: averageOrDefault(
        [settlementPressure, neutralConfidence],
        0.5
      ),
      reciprocity: averageOrDefault([alignmentAverage, 1 - volatility], 0.5),
      source: 'aeon negotiation convergence field',
    },
  });
}

/**
 * Handles the gnosis derive Negotiation Formal Ledger Bundle workflow.
 */
export function deriveNegotiationFormalLedgerBundle(
  analysis: FormalLedgerNegotiationAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerBundle {
  return deriveFormalLedgerBundle(
    createNegotiationFormalLedgerContext(analysis, declaration)
  );
}

/**
 * Creates the Communication Formal Ledger Context.
 */
export function createCommunicationFormalLedgerContext(
  analysis: FormalLedgerCommunicationAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  const rawOutputStreams = analysis.topology.outputStreams;
  const participantCount = Number.isFinite(analysis.topology.participantCount)
    ? Math.max(1, Math.round(analysis.topology.participantCount))
    : 1;
  const outputStreams = (() => {
    if (
      typeof rawOutputStreams === 'number' &&
      Number.isFinite(rawOutputStreams)
    ) {
      return Math.max(1, Math.round(rawOutputStreams));
    }

    return 1;
  })();
  const rawDeficit = Math.max(0, participantCount - outputStreams);
  const agreementRatio = clampUnit(analysis.topology.agreementRatio ?? 0.5);
  const sharedContextUnits = Math.max(
    0,
    analysis.topology.sharedContextUnits ?? rawDeficit * agreementRatio
  );
  const effectiveDeficit = Math.max(0, rawDeficit - sharedContextUnits);
  const unresolvedDeficit =
    rawDeficit === 0 ? 0 : clampUnit(effectiveDeficit / rawDeficit);
  const contextCoverage =
    rawDeficit === 0 ? 1 : clampUnit(1 - unresolvedDeficit);
  const outputCompression =
    participantCount <= 1
      ? 0
      : clampUnit((participantCount - outputStreams) / participantCount);
  const alerts = analysis.safety?.alerts ?? [];
  const alertLoad = averageOrDefault(
    alerts.map((alert) => communicationAlertSeverityScore(alert.severity)),
    analysis.safety?.entropyLevel ?? 0.5
  );
  const actedAlertRatio =
    alerts.length === 0
      ? 0.5
      : clampUnit(
          alerts.filter((alert) => alert.twinTookAction === true).length /
            alerts.length
        );
  const entropyLevel = clampUnit(analysis.safety?.entropyLevel ?? alertLoad);
  const empathySignal = clampUnit(
    analysis.signals.empathySignal ??
      averageOrDefault([agreementRatio, contextCoverage], 0.5)
  );
  const authenticity = clampUnit(
    analysis.signals.authenticity ??
      averageOrDefault([agreementRatio, 1 - entropyLevel, contextCoverage], 0.5)
  );
  const clarificationNeed = clampUnit(
    analysis.signals.clarificationNeed ??
      averageOrDefault(
        [unresolvedDeficit, 1 - agreementRatio, entropyLevel],
        0.5
      )
  );
  const dominanceRisk = clampUnit(
    analysis.signals.dominanceRisk ??
      averageOrDefault([unresolvedDeficit, alertLoad, entropyLevel], 0.5)
  );
  const mergePressure = clampUnit(
    analysis.signals.mergePressure ??
      averageOrDefault(
        [outputCompression, entropyLevel, unresolvedDeficit],
        0.5
      )
  );
  const reciprocitySignal = clampUnit(
    analysis.signals.reciprocitySignal ??
      averageOrDefault(
        [agreementRatio, 1 - dominanceRisk, actedAlertRatio],
        0.5
      )
  );
  const perspectiveBreadth = clampUnit(
    analysis.signals.perspectiveBreadth ??
      averageOrDefault(
        [empathySignal, 1 - dominanceRisk, 1 - clarificationNeed],
        0.5
      )
  );
  const source = analysis.source ?? 'gnosis communication field';

  const community: FormalLedgerCommunityInput = {
    empathy: averageOrDefault([empathySignal, contextCoverage], 0.5),
    belonging: averageOrDefault(
      [authenticity, contextCoverage, 1 - mergePressure],
      0.5
    ),
    dominanceRisk: averageOrDefault([dominanceRisk, alertLoad], 0.5),
    mergePressure: averageOrDefault([mergePressure, unresolvedDeficit], 0.5),
    reciprocity: averageOrDefault(
      [reciprocitySignal, actedAlertRatio, 1 - clarificationNeed],
      0.5
    ),
    source,
  };

  const metacognition: FormalLedgerMetacognitionInput = {
    c0Confidence: averageOrDefault([authenticity, agreementRatio], 0.5),
    c1Calibration: averageOrDefault(
      [1 - clarificationNeed, authenticity, 1 - alertLoad],
      0.5
    ),
    c2Coherence: averageOrDefault(
      [contextCoverage, authenticity, 1 - dominanceRisk],
      0.5
    ),
    c3BiasAwareness: averageOrDefault(
      [perspectiveBreadth, empathySignal, 1 - dominanceRisk],
      0.5
    ),
    source,
  };

  const recoveryInput = createCommunicationRecoveryInput(
    analysis,
    source,
    entropyLevel,
    alertLoad,
    unresolvedDeficit,
    clarificationNeed,
    dominanceRisk,
    authenticity,
    contextCoverage
  );

  return buildFormalLedgerContext(declaration, {
    community,
    metacognition,
    ...(recoveryInput == null ? {} : { recovery: recoveryInput }),
  });
}

