/**
 * Creates the Trust Formal Ledger Context.
 */
export function createTrustFormalLedgerContext(
  analysis: FormalLedgerTrustAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  if (!hasTrustAnalysisSignal(analysis)) {
    return buildFormalLedgerContext(declaration);
  }

  const verifiedActor =
    analysis.authority?.verifiedActor == null
      ? 0.5
      : analysis.authority.verifiedActor
      ? 0.88
      : 0.18;
  const delegationDepth = normalizeCount(
    Math.max(0, analysis.authority?.delegationDepth ?? 0),
    4
  );
  const capabilityCoverage = clampUnit(
    analysis.authority?.capabilityCoverage ??
      averageOrDefault([verifiedActor, 1 - delegationDepth], 0.5)
  );
  const overridePressure = clampUnit(
    analysis.authority?.overridePressure ??
      averageOrDefault([1 - capabilityCoverage, delegationDepth], 0.45)
  );
  const holdCount = normalizeCount(
    Math.max(0, analysis.authority?.holdCount ?? 0),
    4
  );
  const activeHoldRatio = clampUnit(
    analysis.authority?.activeHoldRatio ??
      averageOrDefault([holdCount, overridePressure], holdCount)
  );
  const quarantineRisk = clampUnit(
    analysis.authority?.quarantineRisk ??
      averageOrDefault([activeHoldRatio, overridePressure], 0.4)
  );
  const forgeHoldRisk = clampUnit(
    analysis.authority?.forgeHoldRisk ??
      averageOrDefault([activeHoldRatio, holdCount], 0.35)
  );
  const manipulationLoad = clampUnit(
    analysis.signals.manipulationLoad ??
      averageOrDefault([overridePressure, activeHoldRatio], 0.5)
  );
  const factualCoverage = clampUnit(
    analysis.signals.factualCoverage ??
      averageOrDefault(
        [1 - manipulationLoad, capabilityCoverage, verifiedActor],
        0.5
      )
  );
  const requestClarity = clampUnit(
    analysis.signals.requestClarity ??
      averageOrDefault([factualCoverage, 1 - manipulationLoad], 0.5)
  );
  const impliedPressure = clampUnit(
    analysis.signals.impliedPressure ??
      averageOrDefault([manipulationLoad, 1 - requestClarity], 0.5)
  );
  const authenticityGap = clampUnit(
    analysis.signals.authenticityGap ??
      averageOrDefault([manipulationLoad, 1 - factualCoverage], 0.5)
  );
  const evidenceBreadth = clampUnit(
    analysis.signals.evidenceBreadth ??
      averageOrDefault([factualCoverage, requestClarity], 0.5)
  );
  const authorityStrain = averageOrDefault(
    [overridePressure, activeHoldRatio, quarantineRisk, forgeHoldRisk],
    0.5
  );
  const source = analysis.source ?? 'gnosis trust analysis';

  return buildFormalLedgerContext(declaration, {
    community: {
      empathy: averageOrDefault(
        [factualCoverage, requestClarity, 1 - manipulationLoad],
        0.5
      ),
      belonging: averageOrDefault(
        [verifiedActor, capabilityCoverage, 1 - authorityStrain],
        0.5
      ),
      dominanceRisk: averageOrDefault(
        [overridePressure, manipulationLoad, impliedPressure],
        0.5
      ),
      mergePressure: averageOrDefault(
        [impliedPressure, delegationDepth, activeHoldRatio],
        0.5
      ),
      reciprocity: averageOrDefault(
        [capabilityCoverage, factualCoverage, 1 - manipulationLoad],
        0.5
      ),
      source,
    },
    metacognition: {
      c0Confidence: averageOrDefault(
        [verifiedActor, factualCoverage, capabilityCoverage],
        0.5
      ),
      c1Calibration: averageOrDefault(
        [requestClarity, evidenceBreadth, 1 - authenticityGap],
        0.5
      ),
      c2Coherence: averageOrDefault(
        [factualCoverage, 1 - activeHoldRatio, capabilityCoverage],
        0.5
      ),
      c3BiasAwareness: averageOrDefault(
        [evidenceBreadth, 1 - manipulationLoad, 1 - impliedPressure],
        0.5
      ),
      source,
    },
    recovery: {
      stressLoad: averageOrDefault(
        [manipulationLoad, authorityStrain, impliedPressure],
        0.5
      ),
      sleepDebt: averageOrDefault(
        [overridePressure, activeHoldRatio, quarantineRisk],
        0.45
      ),
      restoration: averageOrDefault(
        [1 - authorityStrain, capabilityCoverage, verifiedActor],
        0.5
      ),
      forgiveness: averageOrDefault(
        [1 - authenticityGap, factualCoverage, 1 - overridePressure],
        0.5
      ),
      breathRegulation: averageOrDefault(
        [1 - manipulationLoad, 1 - impliedPressure, 1 - authorityStrain],
        0.45
      ),
      rumination: averageOrDefault(
        [manipulationLoad, activeHoldRatio, authenticityGap],
        0.5
      ),
      source,
    },
  });
}

