/**
 * Creates the Behavior Formal Ledger Context.
 */
export function createBehaviorFormalLedgerContext(
  analysis: FormalLedgerBehaviorAnalysis,
  declaration?: FormalLedgerServiceDeclaration
): FormalLedgerContext {
  if (!hasBehaviorAnalysisSignal(analysis)) {
    return buildFormalLedgerContext(declaration);
  }

  const confidences = analysis.detections
    .map((detection) => detection.confidence)
    .filter((value): value is number => Number.isFinite(value))
    .map(clampUnit);
  const negativeConfidences = analysis.detections
    .filter((detection) => detection.valence === 'negative')
    .map((detection) => detection.confidence)
    .filter((value): value is number => Number.isFinite(value))
    .map(clampUnit);
  const positiveConfidences = analysis.detections
    .filter((detection) => detection.valence === 'positive')
    .map((detection) => detection.confidence)
    .filter((value): value is number => Number.isFinite(value))
    .map(clampUnit);
  const neutralConfidences = analysis.detections
    .filter((detection) => detection.valence === 'neutral')
    .map((detection) => detection.confidence)
    .filter((value): value is number => Number.isFinite(value))
    .map(clampUnit);
  const matchedTermLoads = analysis.detections
    .map((detection) => detection.matchedTermCount)
    .filter((value): value is number => Number.isFinite(value))
    .map((value) => normalizeCount(Math.max(0, value), 5));
  const detectionDensity = normalizeCount(analysis.detections.length, 5);
  const interventionCoverage =
    analysis.detections.length === 0
      ? normalizeCount(analysis.summary?.actionableCount ?? 0, 3)
      : clampUnit(
          analysis.detections.filter(
            (detection) => detection.hasIntervention === true
          ).length / analysis.detections.length
        );
  const recommendationCoverage = normalizeCount(
    analysis.recommendationCount ?? analysis.summary?.actionableCount ?? 0,
    4
  );
  const topConfidence = averageOrDefault(confidences, 0.5);
  const negativeConfidence = averageOrDefault(negativeConfidences, 0);
  const positiveConfidence = averageOrDefault(positiveConfidences, 0);
  const neutralConfidence = averageOrDefault(neutralConfidences, 0);
  const matchedTermLoad = averageOrDefault(matchedTermLoads, detectionDensity);
  const riskLoad = behaviorRiskLevelScore(analysis.summary?.riskLevel);
  const dominantValencePressure = behaviorDominantValenceScore(
    analysis.summary?.dominantValence
  );
  const loopInstability = averageOrDefault(
    [detectionDensity, matchedTermLoad, riskLoad],
    0.5
  );
  const negativeLoad = averageOrDefault(
    [negativeConfidence, riskLoad, dominantValencePressure.negative],
    0.5
  );
  const positiveSupport = averageOrDefault(
    [
      positiveConfidence,
      recommendationCoverage,
      interventionCoverage,
      dominantValencePressure.positive,
    ],
    0.4
  );
  const ambiguityLoad = averageOrDefault(
    [
      neutralConfidence,
      dominantValencePressure.ambiguous,
      1 - topConfidence,
      1 - recommendationCoverage,
    ],
    0.45
  );
  const dominanceRisk = averageOrDefault(
    [negativeLoad, riskLoad, loopInstability],
    0.5
  );
  const source = analysis.source ?? 'gnosis behavior analysis';

  return buildFormalLedgerContext(declaration, {
    community: {
      empathy: averageOrDefault(
        [positiveSupport, 1 - negativeLoad, interventionCoverage],
        0.5
      ),
      belonging: averageOrDefault(
        [positiveSupport, 1 - negativeLoad, 1 - ambiguityLoad],
        0.5
      ),
      dominanceRisk,
      mergePressure: averageOrDefault(
        [loopInstability, ambiguityLoad, negativeLoad],
        0.5
      ),
      reciprocity: averageOrDefault(
        [interventionCoverage, recommendationCoverage, 1 - negativeLoad],
        0.5
      ),
      source,
    },
    metacognition: {
      c0Confidence: averageOrDefault(
        [topConfidence, recommendationCoverage, 1 - ambiguityLoad],
        0.5
      ),
      c1Calibration: averageOrDefault(
        [interventionCoverage, matchedTermLoad, 1 - ambiguityLoad],
        0.5
      ),
      c2Coherence: averageOrDefault(
        [1 - loopInstability, positiveSupport, 1 - negativeLoad],
        0.5
      ),
      c3BiasAwareness: averageOrDefault(
        [recommendationCoverage, interventionCoverage, 1 - negativeLoad],
        0.5
      ),
      source,
    },
    recovery: {
      stressLoad: averageOrDefault(
        [negativeLoad, riskLoad, loopInstability],
        0.5
      ),
      sleepDebt: averageOrDefault(
        [negativeLoad, ambiguityLoad, detectionDensity],
        0.45
      ),
      restoration: averageOrDefault(
        [positiveSupport, interventionCoverage, 1 - negativeLoad],
        0.5
      ),
      forgiveness: averageOrDefault(
        [positiveSupport, 1 - dominanceRisk, 1 - negativeLoad],
        0.5
      ),
      breathRegulation: averageOrDefault(
        [1 - negativeLoad, interventionCoverage, 1 - riskLoad],
        0.45
      ),
      rumination: averageOrDefault(
        [negativeLoad, ambiguityLoad, detectionDensity],
        0.5
      ),
      source,
    },
  });
}

