function createMetacognitionReport(
  input?: FormalLedgerMetacognitionInput
): FormalLedgerFamilyReport {
  if (input == null || !hasAnyDefinedValue(input)) {
    return createInactiveReport('metacognition');
  }

  const c0Confidence = clampUnit(input.c0Confidence ?? 0.5);
  const c1Calibration = clampUnit(input.c1Calibration ?? 0.5);
  const c2Coherence = clampUnit(input.c2Coherence ?? 0.5);
  const c3BiasAwareness = clampUnit(input.c3BiasAwareness ?? 0.5);

  const primitives = {
    fork: average([c0Confidence, c3BiasAwareness]),
    race: c1Calibration,
    fold: c2Coherence,
    vent: c3BiasAwareness,
    interfere: average([c1Calibration, c2Coherence, c3BiasAwareness]),
  } satisfies Record<FormalLedgerPrimitiveId, number>;
  const states = toPrimitiveStates(primitives, {
    fork: 'Observation remains broad enough to preserve alternate explanations.',
    race: 'Calibration separates confidence from wishful certainty.',
    fold: 'Contradictions are reconciled instead of being stacked indefinitely.',
    vent: 'Old self-stories can be released when better evidence arrives.',
    interfere:
      'The system learns from its own mistakes instead of repeating them with new language.',
  });

  return createActiveReport(
    'metacognition',
    states,
    `C0-C3 is currently anchored by calibration ${c1Calibration.toFixed(
      2
    )} and coherence ${c2Coherence.toFixed(2)}.`,
    [
      createDiagnostic(
        'metacognition',
        'calibration',
        'Calibration gap',
        'Confidence should not outrun calibration.',
        c1Calibration < 0.45 ? 'high' : 'moderate',
        'race',
        c1Calibration
      ),
      createDiagnostic(
        'metacognition',
        'coherence',
        'Coherence check',
        'Cross-layer contradictions should be surfaced before they are narrated as certainty.',
        c2Coherence < 0.45 ? 'high' : 'moderate',
        'fold',
        c2Coherence
      ),
    ],
    [
      {
        id: 'metacognition-wellness',
        familyId: 'metacognition',
        audience: 'wellness',
        title: 'Metacognitive state',
        summary:
          c2Coherence < 0.45
            ? 'Slow down and reconcile contradictions before treating the current self-story as settled.'
            : 'Your reflection loop is usable, but it still benefits from explicit evidence and bias checks.',
        detail:
          'Observation is not the same thing as certainty. C1-C3 exists to keep those apart.',
      },
      {
        id: 'metacognition-research',
        familyId: 'metacognition',
        audience: 'research',
        title: 'Daisy-chain state',
        summary:
          'MetacognitiveDaisyChain supplies the C0-C3 convergence language for calibration, coherence, and bias-aware update.',
        detail:
          'This family is the platform’s theorem-backed bridge from raw profile prediction to self-correcting personality reconstruction.',
      },
    ],
    createMetacognitionRecommendations(
      c1Calibration,
      c2Coherence,
      c3BiasAwareness
    ),
    [
      createUnmappedSegment(
        'c0',
        'C0 confidence',
        c0Confidence,
        'Base-model confidence shapes observation coverage before higher-order checks.'
      ),
    ],
    {
      c0Confidence,
      c1Calibration,
      c2Coherence,
      c3BiasAwareness,
    }
  );
}

function createRecoveryReport(
  input?: FormalLedgerRecoveryInput
): FormalLedgerFamilyReport {
  if (input == null || !hasAnyDefinedValue(input)) {
    return createInactiveReport('recovery');
  }

  const stressLoad = clampUnit(input.stressLoad ?? 0.5);
  const sleepDebt = clampUnit(input.sleepDebt ?? 0.5);
  const restoration = clampUnit(input.restoration ?? 0.5);
  const forgiveness = clampUnit(input.forgiveness ?? 0.5);
  const breathRegulation = clampUnit(input.breathRegulation ?? 0.5);
  const rumination = clampUnit(input.rumination ?? 0.5);

  const primitives = {
    fork: average([1 - stressLoad, forgiveness]),
    race: average([breathRegulation, 1 - rumination]),
    fold: average([restoration, 1 - stressLoad]),
    vent: average([
      restoration,
      forgiveness,
      breathRegulation,
      1 - sleepDebt,
      1 - rumination,
    ]),
    interfere: average([breathRegulation, restoration, 1 - rumination]),
  } satisfies Record<FormalLedgerPrimitiveId, number>;
  const states = toPrimitiveStates(primitives, {
    fork: 'The system still has room to see recovery options instead of only threat.',
    race: 'Breath and attention can separate urgent noise from the next useful action.',
    fold: 'Recovery habits can stabilize instead of dissolving under load.',
    vent: 'Stress can leave the system without erasing signal or storing extra debt.',
    interfere:
      'The body and story update each other instead of escalating together.',
  });

  const diagnostics: FormalLedgerDiagnostic[] = [
    createDiagnostic(
      'recovery',
      'sleep',
      'Sleep debt',
      'Sleep debt is a first-class recovery constraint, not a side issue.',
      sleepDebt > 0.6 ? 'high' : 'moderate',
      'vent',
      sleepDebt
    ),
    createDiagnostic(
      'recovery',
      'rumination',
      'Rumination load',
      'Rumination keeps vent debt live long after the original signal should have discharged.',
      rumination > 0.6 ? 'high' : 'moderate',
      'race',
      rumination
    ),
  ];

  if (stressLoad > 0.65) {
    diagnostics.push(
      createDiagnostic(
        'recovery',
        'stress',
        'Stress load',
        'Stress is high enough that recovery needs to precede interpretation and productivity.',
        'high',
        'fold',
        stressLoad
      )
    );
  }

  return createActiveReport(
    'recovery',
    states,
    `Vent debt is being set by sleep debt ${sleepDebt.toFixed(
      2
    )}, stress ${stressLoad.toFixed(2)}, and rumination ${rumination.toFixed(
      2
    )}.`,
    diagnostics,
    [
      {
        id: 'recovery-wellness',
        familyId: 'recovery',
        audience: 'wellness',
        title: 'Recovery posture',
        summary:
          sleepDebt > 0.6 || stressLoad > 0.65
            ? 'Protect sleep and regulate first. Insight work is downstream of basic recovery.'
            : 'Recovery is available, but it still depends on discharging stress instead of rehearsing it.',
        detail:
          'Breath, sleep, and forgiving release are the fast path for lowering vent debt in this family.',
      },
      {
        id: 'recovery-research',
        familyId: 'recovery',
        audience: 'research',
        title: 'Sleep-debt / vent surface',
        summary:
          'SleepDebt and vent-restoration mappings are treated as theorem-backed recovery constraints, not wellness garnish.',
        detail:
          'This family is the formal bridge from Chapter 17 mindfulness language into service-ready recovery diagnostics.',
      },
    ],
    createRecoveryRecommendations(sleepDebt, stressLoad, rumination),
    [
      createUnmappedSegment(
        'stressLoad',
        'Stress load',
        stressLoad,
        'Stress is a driver of vent debt and fold instability, not a primitive itself.'
      ),
    ],
    {
      stressLoad,
      sleepDebt,
      restoration,
      forgiveness,
      breathRegulation,
      rumination,
    }
  );
}

function createProbabilityReport(
  input?: FormalLedgerProbabilityInput
): FormalLedgerFamilyReport {
  if (input == null || !hasAnyDefinedValue(input)) {
    return createInactiveReport('probability');
  }

  const hypothesisBreadth = normalizeCount(input.hypothesisCount ?? 0, 4);
  const topPosterior = clampUnit(input.topPosterior ?? 0.5);
  const runnerUpPosterior = clampUnit(input.runnerUpPosterior ?? 0.5);
  const posteriorLead = clampUnit(topPosterior - runnerUpPosterior);
  const evidenceTraceability = clampUnit(input.evidenceTraceability ?? 0.5);
  const unsupportedClaimRatio = clampUnit(input.unsupportedClaimRatio ?? 0);
  const validationStrength = clampUnit(input.validationStrength ?? 0.25);
  const updateStrength = clampUnit(input.updateStrength ?? 0);
  const convergenceRate = clampUnit(input.convergenceRate ?? 0);
  const auditStrength = average([
    evidenceTraceability,
    1 - unsupportedClaimRatio,
  ]);

  const primitives = {
    fork: average([hypothesisBreadth, auditStrength]),
    race: average([posteriorLead, validationStrength]),
    fold: average([topPosterior, convergenceRate, validationStrength]),
    vent: average([auditStrength, updateStrength]),
    interfere: average([
      updateStrength,
      validationStrength,
      evidenceTraceability,
    ]),
  } satisfies Record<FormalLedgerPrimitiveId, number>;
  const states = toPrimitiveStates(primitives, {
    fork: 'Multiple live hypotheses remain visible without collapsing the field too early.',
    race: 'The posterior can separate signal from noise instead of leaving every claim equally plausible.',
    fold: 'Inference can close on a working belief state without pretending the evidence is final.',
    vent: 'Unsupported or stale claims can be released instead of being carried as probability debt.',
    interfere:
      'Evidence changes the belief state rather than being absorbed without updating the model.',
  });

  const diagnostics: FormalLedgerDiagnostic[] = [
    createDiagnostic(
      'probability',
      'separation',
      'Posterior separation',
      'The posterior should meaningfully separate the leading hypothesis from the nearest alternative.',
      posteriorLead < 0.12 ? 'high' : posteriorLead < 0.22 ? 'moderate' : 'low',
      'race',
      posteriorLead
    ),
    createDiagnostic(
      'probability',
      'traceability',
      'Evidence traceability',
      'Probability claims should preserve provenance, citations, and calibration lineage.',
      evidenceTraceability < 0.55
        ? 'high'
        : evidenceTraceability < 0.75
        ? 'moderate'
        : 'low',
      'vent',
      evidenceTraceability
    ),
    createDiagnostic(
      'probability',
      'validation',
      'Validation pressure',
      'Posterior confidence should not outrun holdout and negative-control validation.',
      validationStrength < 0.45
        ? 'high'
        : validationStrength < 0.65
        ? 'moderate'
        : 'low',
      'fold',
      validationStrength
    ),
  ];

  if (unsupportedClaimRatio > 0.25) {
    diagnostics.push(
      createDiagnostic(
        'probability',
        'unsupported',
        'Unsupported-claim load',
        'Too much of the probability surface is still being asserted without evidence support.',
        unsupportedClaimRatio > 0.5 ? 'high' : 'moderate',
        'vent',
        unsupportedClaimRatio
      )
    );
  }

  return createActiveReport(
    'probability',
    states,
    `Probability posture is set by posterior lead ${posteriorLead.toFixed(
      2
    )}, traceability ${evidenceTraceability.toFixed(
      2
    )}, and validation ${validationStrength.toFixed(2)}.`,
    diagnostics,
    [
      {
        id: 'probability-wellness',
        familyId: 'probability',
        audience: 'wellness',
        title: 'Probability posture',
        summary:
          posteriorLead < 0.12 || updateStrength < 0.12
            ? 'Keep multiple hypotheses live. The current evidence is not yet separating the field enough to close on one story.'
            : validationStrength < 0.5
            ? 'The posterior is useful for reflection, but not yet strong enough for high-confidence commitment.'
            : 'The field is differentiating cleanly enough to act, as long as evidence lineage remains visible.',
        detail:
          'In Maybe, Solomonoff, Bayesian, frequentist, and retrocausal layers are one walk across the same primitive surface.',
      },
      {
        id: 'probability-research',
        familyId: 'probability',
        audience: 'research',
        title: 'Maybe four-layer state',
        summary:
          'This family formalizes probability as a layered void walk rather than a detached scalar score.',
        detail:
          'Source lineage: @a0n/maybe, the Solomonoff/Bayesian/Frequentist/Retrocausal layer stack, and the Gnosis formal-ledger bridge.',
      },
    ],
    createProbabilityRecommendations(
      posteriorLead,
      evidenceTraceability,
      unsupportedClaimRatio,
      validationStrength,
      updateStrength
    ),
    [
      createUnmappedSegment(
        'hypothesisCount',
        'Hypothesis count',
        hypothesisBreadth,
        'How many live hypotheses are in play before primitive reduction.'
      ),
      createUnmappedSegment(
        'topPosterior',
        'Top posterior',
        topPosterior,
        'The current leading posterior mass before it is reduced to primitive health.'
      ),
      createUnmappedSegment(
        'runnerUpPosterior',
        'Runner-up posterior',
        runnerUpPosterior,
        'The nearest competing posterior mass in the current field.'
      ),
    ],
    {
      hypothesisCount: input.hypothesisCount ?? 0,
      topPosterior,
      runnerUpPosterior,
      posteriorLead,
      evidenceTraceability,
      unsupportedClaimRatio,
      validationStrength,
      updateStrength,
      convergenceRate,
    }
  );
}

function createCommunicationRecoveryInput(
  analysis: FormalLedgerCommunicationAnalysis,
  source: string,
  entropyLevel: number,
  alertLoad: number,
  unresolvedDeficit: number,
  clarificationNeed: number,
  dominanceRisk: number,
  authenticity: number,
  contextCoverage: number
): FormalLedgerRecoveryInput | undefined {
  const safety = analysis.safety;

  if (
    safety == null ||
    ![
      safety.stressLoad,
      safety.sleepDebt,
      safety.restorationCapacity,
      safety.breathRegulation,
      safety.ruminationRisk,
    ].some((value) => Number.isFinite(value))
  ) {
    return undefined;
  }

  return {
    stressLoad: clampUnit(
      safety.stressLoad ??
        averageOrDefault([entropyLevel, alertLoad, unresolvedDeficit], 0.5)
    ),
    sleepDebt: clampUnit(safety.sleepDebt ?? 0.5),
    restoration: clampUnit(
      safety.restorationCapacity ??
        averageOrDefault([1 - entropyLevel, contextCoverage], 0.5)
    ),
    forgiveness: averageOrDefault(
      [contextCoverage, 1 - dominanceRisk, authenticity],
      0.5
    ),
    breathRegulation: clampUnit(
      safety.breathRegulation ??
        averageOrDefault([1 - entropyLevel, authenticity], 0.5)
    ),
    rumination: clampUnit(
      safety.ruminationRisk ??
        averageOrDefault([clarificationNeed, unresolvedDeficit], 0.5)
    ),
    source,
  };
}

