function createProbabilityRecommendations(
  posteriorLead: number,
  evidenceTraceability: number,
  unsupportedClaimRatio: number,
  validationStrength: number,
  updateStrength: number
): readonly FormalLedgerRecommendation[] {
  const recommendations: FormalLedgerRecommendation[] = [];

  if (evidenceTraceability < 0.65 || unsupportedClaimRatio > 0.25) {
    recommendations.push({
      id: 'probability-audit',
      familyId: 'probability',
      title: 'Audit evidence lineage',
      rationale:
        'Probability claims become hard to trust when provenance, citations, or calibration are missing.',
      actions: [
        'Add provenance or citation coverage to the unsupported claims first.',
        'Mark any uncalibrated evidence as provisional before using it to close the field.',
      ],
      modalities: ['reflection'],
      priority:
        evidenceTraceability < 0.5 || unsupportedClaimRatio > 0.5
          ? 'urgent'
          : 'stabilize',
    });
  }

  if (updateStrength < 0.12 || posteriorLead < 0.12) {
    recommendations.push({
      id: 'probability-differentiate',
      familyId: 'probability',
      title: 'Add differentiating evidence',
      rationale:
        'When priors and posteriors barely move apart, the field still needs evidence that can actually distinguish the live hypotheses.',
      actions: [
        'Collect one observation that would raise one hypothesis while lowering another.',
        'Keep at least two hypotheses open until the next discriminating signal arrives.',
      ],
      modalities: ['reflection', 'behavioral'],
      priority: 'stabilize',
    });
  }

  if (validationStrength < 0.5) {
    recommendations.push({
      id: 'probability-validate',
      familyId: 'probability',
      title: 'Collect labeled outcomes',
      rationale:
        'Holdout and negative-control validation keep posterior confidence from outrunning the evidence base.',
      actions: [
        'Record the next outcome labels or historical observations needed for validation.',
        'Re-run the analysis only after the holdout surface has enough structure to falsify it.',
      ],
      modalities: ['behavioral'],
      priority: 'urgent',
    });
  }

  return recommendations;
}

