function createActiveReport(
  familyId: FormalLedgerFamilyId,
  primitiveStates: readonly FormalLedgerPrimitiveState[],
  summary: string,
  diagnostics: readonly FormalLedgerDiagnostic[],
  narratives: readonly FormalLedgerNarrative[],
  recommendations: readonly FormalLedgerRecommendation[],
  unmappedSegments: readonly FormalLedgerUnmappedSegment[],
  metadata: Readonly<Record<string, string | number | boolean>>
): FormalLedgerFamilyReport {
  const catalog = FAMILY_CATALOG[familyId];
  const spike = pickPrimitive(primitiveStates, 'highest');
  const balanceScore = calculateBalanceScore(primitiveStates);
  return {
    familyId,
    title: catalog.title,
    active: true,
    summary,
    sources: catalog.sources,
    primitives: primitiveStates,
    diagnostics,
    narratives,
    recommendations,
    visualization: {
      id: `${familyId}-visualization`,
      familyId,
      kind: catalog.kind,
      title: `${catalog.title} visualization`,
      summary,
      primitives: primitiveStates,
      highlightedPrimitiveId: spike.id,
      metrics: {
        balanceScore,
        activeDeficit: spike.deficit,
        referenceAttractor: INV_PHI,
      },
    },
    unmappedSegments,
    metadata,
  };
}

function toPrimitiveStates(
  primitives: Readonly<Record<FormalLedgerPrimitiveId, number>>,
  summaries: Readonly<Record<FormalLedgerPrimitiveId, string>>
): readonly FormalLedgerPrimitiveState[] {
  return FORMAL_LEDGER_PRIMITIVES.map((primitiveId) => {
    const strength = clampUnit(primitives[primitiveId]);
    const deficit = clampUnit(1 - strength);
    return {
      id: primitiveId,
      title: PRIMITIVE_TITLES[primitiveId],
      strength,
      deficit,
      severity: classifySeverity(deficit),
      summary: summaries[primitiveId],
    };
  });
}

function aggregateBundlePrimitives(
  reports: Readonly<Record<FormalLedgerFamilyId, FormalLedgerFamilyReport>>,
  activeFamilies: readonly FormalLedgerFamilyId[]
): readonly FormalLedgerPrimitiveState[] {
  if (activeFamilies.length === 0) {
    return FORMAL_LEDGER_PRIMITIVES.map((primitiveId) => ({
      id: primitiveId,
      title: PRIMITIVE_TITLES[primitiveId],
      strength: 0.5,
      deficit: 0.5,
      severity: 'moderate',
      summary: 'No active family has declared this primitive yet.',
    }));
  }

  return FORMAL_LEDGER_PRIMITIVES.map((primitiveId) => {
    const strengths = activeFamilies.map((familyId) => {
      const state = reports[familyId].primitives.find(
        (primitive) => primitive.id === primitiveId
      );
      return state?.strength ?? 0.5;
    });
    const strength = average(strengths);
    const deficit = clampUnit(1 - strength);
    return {
      id: primitiveId,
      title: PRIMITIVE_TITLES[primitiveId],
      strength,
      deficit,
      severity: classifySeverity(deficit),
      summary:
        'Average primitive state across all active formal-ledger families.',
    };
  });
}

function createCompliance(
  declaration: FormalLedgerServiceDeclaration | undefined,
  activeFamilies: readonly FormalLedgerFamilyId[]
): FormalLedgerBundle['compliance'] {
  if (declaration?.optedOut) {
    return {
      declaredFamilies: [],
      undeclaredFamilies: activeFamilies,
      optedOut: true,
      status: 'opted_out',
    };
  }

  const declaredFamilies = Array.from(
    new Set([...(declaration?.consume ?? []), ...(declaration?.emit ?? [])])
  );
  const undeclaredFamilies = activeFamilies.filter(
    (familyId) => !declaredFamilies.includes(familyId)
  );

  return {
    declaredFamilies,
    undeclaredFamilies,
    optedOut: false,
    status: undeclaredFamilies.length === 0 ? 'declared' : 'undeclared',
  };
}

function createComplianceDiagnostic(
  compliance: FormalLedgerBundle['compliance']
): FormalLedgerDiagnostic | undefined {
  if (compliance.status !== 'undeclared') {
    return undefined;
  }

  return {
    id: 'formal-ledger-compliance',
    familyId: 'voidWalking',
    title: 'Formal ledger declaration gap',
    summary: `Active families must be declared explicitly. Missing: ${compliance.undeclaredFamilies.join(
      ', '
    )}.`,
    severity: 'moderate',
    sourceRefs: ['formal-ledger-service-declaration'],
  };
}

function createDiagnostic(
  familyId: FormalLedgerFamilyId,
  suffix: string,
  title: string,
  summary: string,
  severity: FormalLedgerSeverity,
  primitiveId?: FormalLedgerPrimitiveId,
  value?: number
): FormalLedgerDiagnostic {
  return {
    id: `${familyId}-${suffix}`,
    familyId,
    title,
    summary,
    severity,
    sourceRefs: FAMILY_CATALOG[familyId].sources,
    ...(primitiveId !== undefined ? { primitiveId } : {}),
    ...(value !== undefined ? { value } : {}),
  };
}

function createUnmappedSegment(
  id: string,
  label: string,
  value: number,
  summary: string
): FormalLedgerUnmappedSegment {
  return {
    id,
    label,
    value: clampUnit(value),
    summary,
  };
}

function classifySeverity(deficit: number): FormalLedgerSeverity {
  if (deficit >= 0.67) {
    return 'high';
  }
  if (deficit >= 0.34) {
    return 'moderate';
  }
  return 'low';
}

function calculateBalanceScore(
  states: readonly FormalLedgerPrimitiveState[]
): number {
  const deficits = states.map((state) => state.deficit);
  const min = Math.min(...deficits);
  const max = Math.max(...deficits);
  return clampUnit(1 - (max - min));
}

function pickPrimitive(
  states: readonly FormalLedgerPrimitiveState[],
  direction: 'highest' | 'lowest'
): FormalLedgerPrimitiveState {
  const ordered = [...states].sort((left, right) =>
    direction === 'highest'
      ? right.deficit - left.deficit
      : left.deficit - right.deficit
  );
  const selected = ordered[0];
  if (selected == null) {
    throw new Error('Formal ledger requires at least one primitive state');
  }
  return selected;
}

function hasMetacognitionAnalysisSignal(
  analysis: FormalLedgerMetacognitionAnalysis
): boolean {
  if ((analysis.calibration.layers?.length ?? 0) > 0) {
    return true;
  }

  return [
    analysis.calibration.overallConfidence,
    analysis.coherence.overallCoherence,
    analysis.coherence.coherenceImprovement,
    analysis.coherence.remainingTensionCount,
    analysis.coherence.resolvedContradictionCount,
    ...(analysis.coherence.layerAlignmentScores ?? []),
    analysis.bias.detectedCount,
    analysis.bias.correctedCount,
    analysis.bias.confidenceInCorrections,
    analysis.bias.totalDebiasedDelta,
    analysis.bias.affectedLayerBreadth,
    analysis.quality?.overallQuality,
  ].some((value) => typeof value === 'number' && Number.isFinite(value));
}

function hasJusticeAnalysisSignal(
  analysis: FormalLedgerJusticeAnalysis
): boolean {
  return [
    analysis.evidence.totalThreads,
    analysis.evidence.coveredThreads,
    analysis.evidence.contestedThreads,
    analysis.evidence.uncoveredThreads,
    analysis.evidence.evidenceDeficit,
    analysis.evidence.averageConfidence,
    analysis.adjudication?.remedyCandidateCount,
    analysis.adjudication?.rankedRemedyCount,
    analysis.adjudication?.affectedCommunityCount,
    analysis.adjudication?.communitySignalCount,
    analysis.process?.criticalIssueCount,
    analysis.process?.injusticeTriggerCount,
    analysis.process?.recommendedActionCount,
    analysis.process?.summaryClarity,
  ].some((value) => typeof value === 'number' && Number.isFinite(value));
}

function hasGovernanceAnalysisSignal(
  analysis: FormalLedgerGovernanceAnalysis
): boolean {
  if (analysis.rankings.length > 0) {
    return true;
  }

  return [
    analysis.totalCommunities,
    analysis.process?.consensusLevel,
    analysis.process?.dissentCount,
  ].some((value) => typeof value === 'number' && Number.isFinite(value));
}

function hasTrustAnalysisSignal(analysis: FormalLedgerTrustAnalysis): boolean {
  if (typeof analysis.authority?.verifiedActor === 'boolean') {
    return true;
  }

  return [
    analysis.authority?.delegationDepth,
    analysis.authority?.capabilityCoverage,
    analysis.authority?.overridePressure,
    analysis.authority?.holdCount,
    analysis.authority?.activeHoldRatio,
    analysis.authority?.quarantineRisk,
    analysis.authority?.forgeHoldRisk,
    analysis.signals.manipulationLoad,
    analysis.signals.factualCoverage,
    analysis.signals.impliedPressure,
    analysis.signals.authenticityGap,
    analysis.signals.requestClarity,
    analysis.signals.evidenceBreadth,
  ].some((value) => typeof value === 'number' && Number.isFinite(value));
}

function hasBehaviorAnalysisSignal(
  analysis: FormalLedgerBehaviorAnalysis
): boolean {
  if (analysis.detections.length > 0) {
    return true;
  }

  return [analysis.summary?.actionableCount, analysis.recommendationCount].some(
    (value) => typeof value === 'number' && Number.isFinite(value)
  );
}

function hasRecoveryAnalysisSignal(
  analysis: FormalLedgerRecoveryAnalysis
): boolean {
  if ((analysis.markers?.indicators?.length ?? 0) > 0) {
    return true;
  }
  if ((analysis.markers?.recoveryFactors?.length ?? 0) > 0) {
    return true;
  }

  return [
    analysis.signals.stressLoad,
    analysis.signals.sleepDebt,
    analysis.signals.recoveryTimeMinutes,
    analysis.signals.burnoutRisk,
    analysis.signals.restorationCapacity,
    analysis.signals.forgiveness,
    analysis.signals.breathRegulation,
    analysis.signals.ruminationRisk,
    analysis.signals.confidence,
  ].some((value) => typeof value === 'number' && Number.isFinite(value));
}

function average(values: readonly number[]): number {
  if (values.length === 0) {
    return 0;
  }
  const sum = values.reduce((total, value) => total + value, 0);
  return clampUnit(sum / values.length);
}

function averageOrDefault(values: readonly number[], fallback: number): number {
  return values.length === 0 ? fallback : average(values);
}

function communicationAlertSeverityScore(
  severity: FormalLedgerCommunicationAlertSeverity
): number {
  switch (severity) {
    case 'critical':
      return 1;
    case 'high':
      return 0.8;
    case 'medium':
      return 0.55;
    case 'low':
      return 0.3;
  }
}

function keywordSignalScore(
  texts: readonly string[],
  keywords: readonly string[]
): number {
  if (texts.length === 0 || keywords.length === 0) {
    return 0;
  }

  const normalizedTexts = texts
    .map((text) => text.toLowerCase())
    .filter((text) => text.trim() !== '');
  const hits = normalizedTexts.reduce((total, text) => {
    return total + keywords.filter((keyword) => text.includes(keyword)).length;
  }, 0);

  return normalizeCount(hits, Math.max(3, normalizedTexts.length * 2));
}

function normalizeCount(value: number, saturatesAt: number): number {
  if (!Number.isFinite(value) || saturatesAt <= 0) {
    return 0;
  }
  return clampUnit(value / saturatesAt);
}

function deriveGovernanceTotalCommunities(
  analysis: FormalLedgerGovernanceAnalysis
): number {
  if (
    analysis.totalCommunities != null &&
    Number.isFinite(analysis.totalCommunities)
  ) {
    return analysis.totalCommunities;
  }

  const maxima = analysis.rankings.flatMap((ranking) => {
    const represented =
      ranking.representedCommunities ?? ranking.approvals ?? undefined;
    const uncovered = ranking.uncoveredCommunities ?? undefined;
    const totals = [
      represented != null && uncovered != null ? represented + uncovered : 0,
      ranking.approvals != null && ranking.rejections != null
        ? ranking.approvals + ranking.rejections
        : 0,
    ];

    return totals.filter((value) => Number.isFinite(value));
  });

  return Math.max(1, ...maxima, analysis.rankings.length);
}

function normalizeGovernanceCoverage(
  value: number | undefined,
  totalCommunities: number
): number {
  return value == null ? 0.5 : clampUnit(value / Math.max(1, totalCommunities));
}

function normalizeGovernanceApproval(
  approvals: number | undefined,
  totalCommunities: number
): number {
  return approvals == null
    ? 0.5
    : clampUnit(approvals / Math.max(1, totalCommunities));
}

function normalizeGovernanceRejections(
  rejections: number | undefined,
  totalCommunities: number
): number {
  return rejections == null
    ? 0.5
    : clampUnit(rejections / Math.max(1, totalCommunities));
}

function normalizeGovernanceDeficit(
  ranking: FormalLedgerGovernanceAnalysisRanking,
  totalCommunities: number
): number {
  return clampUnit(
    (ranking.deficit ??
      (ranking.rejections ?? 0) + (ranking.uncoveredCommunities ?? 0)) /
      Math.max(1, totalCommunities)
  );
}

function deriveGovernanceLeadershipSeparation(
  winner: FormalLedgerGovernanceAnalysisRanking,
  runnerUp: FormalLedgerGovernanceAnalysisRanking | undefined,
  totalCommunities: number,
  condorcetWinner: boolean
): number {
  if (runnerUp == null) {
    return condorcetWinner ? 0.9 : 0.75;
  }

  const winnerDeficit =
    winner.deficit ??
    (winner.rejections ?? 0) + (winner.uncoveredCommunities ?? 0);
  const runnerUpDeficit =
    runnerUp.deficit ??
    (runnerUp.rejections ?? 0) + (runnerUp.uncoveredCommunities ?? 0);
  const deficitGap = normalizeCount(
    Math.max(runnerUpDeficit - winnerDeficit, 0),
    Math.max(1, Math.ceil(totalCommunities / 2))
  );
  const approvalLead = normalizeCount(
    Math.max((winner.approvals ?? 0) - (runnerUp.approvals ?? 0), 0),
    Math.max(1, totalCommunities)
  );

  return averageOrDefault(
    [deficitGap, approvalLead, condorcetWinner ? 0.82 : 0.55],
    condorcetWinner ? 0.78 : 0.5
  );
}

function governanceEmotionalCostScore(value: string | undefined): number {
  switch (value?.trim().toLowerCase()) {
    case 'high':
      return 0.86;
    case 'medium':
      return 0.58;
    case 'low':
      return 0.24;
    default:
      return 0.45;
  }
}

function behaviorRiskLevelScore(
  value: FormalLedgerBehaviorRiskLevel | undefined
): number {
  switch (value) {
    case 'high':
      return 0.86;
    case 'moderate':
      return 0.58;
    case 'low':
      return 0.24;
    default:
      return 0.45;
  }
}

function behaviorDominantValenceScore(
  value: FormalLedgerBehaviorValence | 'mixed' | undefined
): {
  readonly positive: number;
  readonly negative: number;
  readonly ambiguous: number;
} {
  switch (value) {
    case 'positive':
      return { positive: 0.84, negative: 0.18, ambiguous: 0.24 };
    case 'negative':
      return { positive: 0.18, negative: 0.84, ambiguous: 0.28 };
    case 'mixed':
      return { positive: 0.52, negative: 0.56, ambiguous: 0.76 };
    case 'neutral':
      return { positive: 0.32, negative: 0.32, ambiguous: 0.52 };
    default:
      return { positive: 0.4, negative: 0.4, ambiguous: 0.5 };
  }
}

function deriveProbabilityValidationStrength(
  validation: FormalLedgerProbabilityAnalysisValidation
): number {
  if (validation.skipped) {
    return 0.25;
  }

  const holdoutCorrelation = clampUnit(
    validation.holdout?.correlation.value ?? 0
  );
  const holdoutError = clampUnit(
    1 - (validation.holdout?.meanAbsoluteError.value ?? 1)
  );
  const negativeControl = clampUnit(
    validation.negativeControl?.degradation ?? 0
  );

  return average([holdoutCorrelation, holdoutError, negativeControl]);
}

function clampUnit(value: number): number {
  if (Number.isNaN(value)) {
    return 0;
  }
  if (value < 0) {
    return 0;
  }
  if (value > 1) {
    return 1;
  }
  return Number(value.toFixed(4));
}

function hasAnyDefinedValue(value: Record<string, unknown>): boolean {
  return Object.values(value).some((entry) => entry != null);
}
